const gateways = [
  ["/market-os/seo-blog-workspace/create","Create article","Open SEO production form","Build an article with keyword, intent, meta, outline, brand rules, schedule and ownership."],
  ["/market-os/seo-blog-workspace/calendar","SEO calendar","Plan monthly production","View the publishing grid, create content by date and control editorial rhythm."],
  ["/market-os/seo-blog-workspace/review","Review queue","Approve or reject content","Inspect drafts, score quality and move articles to approved or revision."],
  ["/market-os/seo-blog-workspace/publishing","Publishing desk","Release approved work","Publish, schedule, hold or reschedule SEO and blog items."],
  ["/market-os/seo-blog-workspace/optimizer","Article optimizer","Improve ranking readiness","Work on keyword, meta, readability, brand-score and internal links."],
  ["/market-os/seo-blog-workspace/topic-clusters","Topic clusters","Control organic strategy","Build clusters, pillars and supporting articles for SEO domination."],
  ["/market-os/seo-blog-workspace/analytics","Analytics","Read organic performance","Track rankings, clicks, impressions, conversion impact and weak pages."],
  ["/market-os/seo-blog-workspace/linking","Internal linking","Strengthen authority flow","Plan internal links and identify pages that need link support."],
  ["/market-os/seo-blog-workspace/brand-governance","Brand governance","Protect communication quality","Control CTA, medical sensitivity, premium tone and editorial compliance."],
]

function Header({total,urgent,review,ready,onReset}:{total:number; urgent:number; review:number; ready:number; onReset:()=>void}){return <section className="overflow-hidden rounded-[2rem] border border-slate-900 bg-white text-slate-950 shadow-2xl shadow-slate-200"><div className="grid gap-8 p-6 lg:grid-cols-[1.4fr_.8fr] lg:p-8"><div><div className="flex flex-wrap gap-2"><span className="rounded-full border border-slate-200 bg-white/10 px-3 py-1 text-xs font-black uppercase tracking-widest text-slate-950">Market-OS</span><span className="rounded-full border border-slate-200 bg-white/10 px-3 py-1 text-xs font-black uppercase tracking-widest text-slate-950">SEO Blog Workspace</span><span className="rounded-full border border-sky-300/30 bg-sky-400/10 px-3 py-1 text-xs font-black uppercase tracking-widest text-sky-100">Organic Growth</span></div><h1 className="mt-5 max-w-5xl text-4xl font-black leading-tight tracking-tight text-slate-950 md:text-6xl">Senior SEO and blog production command center.</h1><p className="mt-5 max-w-4xl text-base font-semibold leading-8 text-slate-700 md:text-lg">A corporate workspace for SEO managers, blog leads and brand communication executives to create, optimize, review, schedule, publish and improve organic content with full operational control.</p><div className="mt-7 flex flex-wrap gap-3"><Button href="/market-os/seo-blog-workspace/create" kind="primary">+ Create article</Button><Button href="/market-os/seo-blog-workspace/calendar" kind="dark">Open calendar</Button><Button href="/market-os/seo-blog-workspace/optimizer" kind="dark">Optimizer</Button><Button onClick={onReset}>Reset workspace</Button></div></div><div className="grid gap-3"><div className="rounded-3xl border border-slate-200 bg-white/10 p-5"><p className="text-xs font-black uppercase tracking-widest text-slate-600">Active articles</p><p className="mt-2 text-4xl font-black text-slate-950">{total}</p><p className="text-sm font-bold text-slate-600">Shared SEO store</p></div><div className="grid grid-cols-3 gap-3"><div className="rounded-2xl border border-slate-200 bg-white/10 p-4"><p className="text-xs font-black uppercase text-slate-600">Urgent</p><p className="mt-2 text-2xl font-black text-slate-950">{urgent}</p></div><div className="rounded-2xl border border-slate-200 bg-white/10 p-4"><p className="text-xs font-black uppercase text-slate-600">Review</p><p className="mt-2 text-2xl font-black text-slate-950">{review}</p></div><div className="rounded-2xl border border-slate-200 bg-white/10 p-4"><p className="text-xs font-black uppercase text-slate-600">Ready</p><p className="mt-2 text-2xl font-black text-slate-950">{ready}</p></div></div></div></div></section>}
function Section({eyebrow,title,desc,action}:{eyebrow:string; title:string; desc?:string; action?:React.ReactNode}){return <div className="flex flex-col gap-4 md:flex-row md:items-end md:justify-between"><div><p className="text-xs font-black uppercase tracking-[0.25em] text-sky-600">{eyebrow}</p><h2 className="mt-2 text-2xl font-black tracking-tight text-slate-950 md:text-3xl">{title}</h2>{desc?<p className="mt-2 max-w-3xl text-sm font-semibold leading-6 text-slate-600">{desc}</p>:null}</div>{action?<div className="flex flex-wrap gap-2">{action}</div>:null}</div>}
function Gateway(){return <Panel className="p-5"><Section eyebrow="Workspace gateways" title="Action routes for senior SEO operators" desc="Each card opens a real production subpage where that specific work is completed."/><div className="mt-5 grid gap-4 md:grid-cols-2 xl:grid-cols-3">{gateways.map((g,i)=><Link key={g[0]} href={g[0]} className={cx("group rounded-3xl border p-5 shadow-sm transition hover:-translate-y-1 hover:shadow-xl",i===0?"border-slate-950 bg-white text-slate-950":"border-slate-200 bg-white text-slate-950")}><div className="flex items-start justify-between"><div><p className={cx("text-xs font-black uppercase tracking-[0.2em]",i===0?"text-slate-950/60":"text-sky-600")}>{g[2]}</p><h3 className={cx("mt-3 text-xl font-black",i===0?"text-slate-950":"text-slate-950")}>{g[1]}</h3></div><span className={cx("rounded-full px-3 py-1 text-xs font-black",i===0?"bg-white text-slate-950":"bg-white text-slate-950")}>Open</span></div><p className={cx("mt-4 text-sm font-semibold leading-6",i===0?"text-slate-950/75":"text-slate-600")}>{g[3]}</p></Link>)}</div></Panel>}
function Filters({query,setQuery,status,setStatus,channel,setChannel,view,setView,focus,setFocus}:{query:string;setQuery:(v:string)=>void;status:string;setStatus:(v:string)=>void;channel:string;setChannel:(v:string)=>void;view:View;setView:(v:View)=>void;focus:Focus;setFocus:(v:Focus)=>void}){return <Panel className="p-5"><div className="grid gap-4 xl:grid-cols-[1.2fr_.55fr_.65fr_.7fr_.75fr]"><input className={inputClass} value={query} onChange={e=>setQuery(e.target.value)} placeholder="Search title, keyword, cluster, owner, audience..."/><select className={inputClass} value={status} onChange={e=>setStatus(e.target.value)}><option value="all">All statuses</option>{[...statuses,"archived","revision"].map(s=><option key={s} value={s}>{label(s)}</option>)}</select><select className={inputClass} value={channel} onChange={e=>setChannel(e.target.value)}><option value="all">All channels</option>{channels.map(c=><option key={c}>{c}</option>)}</select><select className={inputClass} value={view} onChange={e=>setView(e.target.value as View)}><option value="command">Command</option><option value="pipeline">Pipeline</option><option value="table">Table</option><option value="calendar">Calendar preview</option><option value="intelligence">Intelligence</option></select><select className={inputClass} value={focus} onChange={e=>setFocus(e.target.value as Focus)}><option value="all">All focus</option><option value="urgent">Urgent</option><option value="review">Review</option><option value="publishing">Publishing</option><option value="brand">Brand</option><option value="growth">Growth</option></select></div></Panel>}
function Pipeline({items,store,onAdvance,onArchive}:{items:SeoArticle[];store:any;onAdvance:(id:string)=>void;onArchive:(id:string)=>void}){return <Panel className="p-5"><Section eyebrow="SEO pipeline" title="From keyword idea to published article" desc="Move articles across a synchronized SEO production workflow." action={<Button href="/market-os/seo-blog-workspace/create" kind="primary">+ New article</Button>}/><div className="mt-5 grid gap-4 xl:grid-cols-7">{statuses.map(s=><div key={s} className="min-h-[300px] rounded-3xl border border-slate-200 bg-slate-50 p-4"><div className="flex justify-between"><div><h3 className="text-sm font-black text-slate-950">{label(s)}</h3><p className="text-xs font-bold text-slate-9500">{items.filter(i=>i.status===s).length} item(s)</p></div><Badge>{items.filter(i=>i.status===s).length}</Badge></div><div className="mt-4 space-y-3">{items.filter(i=>i.status===s).slice(0,4).map(a=><div key={a.id} className="rounded-2xl border border-slate-200 bg-white p-4 shadow-sm"><div className="flex flex-wrap gap-2"><span className={cx("rounded-full border px-2 py-1 text-[11px] font-black uppercase",statusTone(a.status))}>{label(a.status)}</span><Badge kind={a.priority==="Critical"?"danger":a.priority==="High"?"warning":"default"}>{a.priority}</Badge></div><Link href={`/market-os/seo-blog-workspace/${a.id}`} className="mt-3 block text-sm font-black leading-5 text-slate-950 hover:underline">{a.title}</Link><p className="mt-2 text-xs font-bold text-slate-9500">{a.primaryKeyword}</p><div className="mt-3"><div className="mb-1 flex justify-between text-[11px] font-black uppercase text-slate-500"><span>Readiness</span><span>{Math.round(articleReadiness(a,store.tasks,store.rules))}%</span></div><Meter value={articleReadiness(a,store.tasks,store.rules)}/></div><div className="mt-3 flex flex-wrap gap-2"><button onClick={()=>onAdvance(a.id)} className="rounded-xl bg-white px-3 py-2 text-xs font-black text-slate-950">Next</button><Link href={`/market-os/seo-blog-workspace/${a.id}/edit`} className="rounded-xl border border-slate-200 px-3 py-2 text-xs font-black text-slate-700">Edit</Link><button onClick={()=>onArchive(a.id)} className="rounded-xl border border-slate-200 px-3 py-2 text-xs font-black text-slate-700">Archive</button></div></div>)}{items.filter(i=>i.status===s).length===0?<div className="rounded-2xl border border-dashed border-slate-300 p-6 text-center text-sm font-bold text-slate-9500">No articles</div>:null}</div></div>)}</div></Panel>}
function Intelligence({store}:{store:any}){const overdue=store.articles.filter(isOverdue); const review=store.articles.filter((a:SeoArticle)=>["review","draft"].includes(a.status)); const ready=store.articles.filter((a:SeoArticle)=>canPublish(a,store.tasks,store.rules)); const low=store.articles.filter((a:SeoArticle)=>a.seoScore<75||a.brandScore<75); const move=overdue.length?"Clear overdue SEO production blockers":review.length?"Review drafts and approve publishable work":ready.length?"Move approved articles into publishing":low.length?"Optimize low-score articles":"Create next strategic cluster article"; return <Panel className="p-5"><Section eyebrow="Decision intelligence" title="SEO manager next move" desc="State-based recommendations using ranking, readiness, overdue tasks, review pressure and brand risk."/><div className="mt-5 rounded-3xl bg-white p-6 text-slate-950"><p className="text-xs font-black uppercase tracking-[0.2em] text-slate-600">Recommended action</p><h3 className="mt-3 text-2xl font-black text-slate-950">{move}</h3><p className="mt-3 text-sm font-semibold leading-6 text-slate-600">Use this as a practical assistant panel: it points to the next operational decision, not fake automation.</p></div><div className="mt-4 grid gap-3 md:grid-cols-2"><Link href="/market-os/seo-blog-workspace/review" className="rounded-2xl border border-amber-200 bg-amber-50 p-4 text-sm font-black text-amber-800">Review pressure: {review.length}</Link><Link href="/market-os/seo-blog-workspace/publishing" className="rounded-2xl border border-emerald-200 bg-emerald-50 p-4 text-sm font-black text-emerald-800">Publishable: {ready.length}</Link><Link href="/market-os/seo-blog-workspace/optimizer" className="rounded-2xl border border-red-200 bg-red-50 p-4 text-sm font-black text-red-800">Optimization risk: {low.length}</Link><Link href="/market-os/seo-blog-workspace/topic-clusters" className="rounded-2xl border border-sky-200 bg-sky-50 p-4 text-sm font-black text-sky-800">Clusters: {store.clusters.length}</Link></div></Panel>}

function SignalLibrary(){return <Panel className="p-5"><Section eyebrow="Executive operating signals" title="SEO management playbook" desc="A compact slice of the embedded SEO operating playbook for senior managers."/><div className="mt-5 grid gap-3 md:grid-cols-2 xl:grid-cols-3">{SEO_EXECUTIVE_SIGNALS.slice(0,6).map(s=><div key={s.id} className="rounded-2xl border border-slate-200 bg-slate-50 p-4"><p className="text-xs font-black uppercase tracking-wider text-sky-600">{s.id}</p><h3 className="mt-2 font-black text-slate-950">{s.area}</h3><p className="mt-2 text-xs font-bold leading-5 text-slate-9500">{s.purpose}</p></div>)}</div></Panel>}

function CalendarMini({items}:{items:SeoArticle[]}){const d=new Date(), y=d.getFullYear(), m=d.getMonth(); const first=new Date(y,m,1).getDay(); const days=new Date(y,m+1,0).getDate(); const cells=Array.from({length:42},(_,i)=>{const day=i-first+1; const date=new Date(y,m,day); const iso=date.toISOString().slice(0,10); return {i,day,inMonth:day>=1&&day<=days,iso}}); return <Panel className="p-5"><Section eyebrow="Calendar preview" title="Monthly publishing map" desc="Open the full calendar for creation by date, rescheduling and operational planning." action={<Button href="/market-os/seo-blog-workspace/calendar" kind="primary">Open full calendar</Button>}/><div className="mt-5 grid grid-cols-7 gap-2 text-center text-xs font-black uppercase text-slate-500">{["Sun","Mon","Tue","Wed","Thu","Fri","Sat"].map(x=><div key={x}>{x}</div>)}</div><div className="mt-2 grid grid-cols-7 gap-2">{cells.map(c=>{const list=items.filter(a=>a.scheduledDate===c.iso); return <div key={c.i} className={cx("min-h-[90px] rounded-2xl border p-2",c.inMonth?"border-slate-200 bg-white":"border-slate-100 bg-slate-50 text-slate-600")}><p className="text-xs font-black">{c.inMonth?c.day:""}</p><div className="mt-2 space-y-1">{list.slice(0,2).map(a=><Link key={a.id} href={`/market-os/seo-blog-workspace/${a.id}`} className="block truncate rounded-lg bg-white px-2 py-1 text-[10px] font-black text-slate-950">{a.title}</Link>)}</div></div>})}</div></Panel>}

export default function SeoBlogWorkspace(){
 const {store,commit,reset}=useSeoStore(); const [query,setQuery]=React.useState(""); const [status,setStatus]=React.useState("all"); const [channel,setChannel]=React.useState("all"); const [view,setView]=React.useState<View>("command"); const [focus,setFocus]=React.useState<Focus>("all");
 const filtered=React.useMemo(()=>store.articles.filter(a=>{const h=`${a.title} ${a.primaryKeyword} ${a.cluster} ${a.owner} ${a.audience} ${a.channel}`.toLowerCase(); const mq=query?h.includes(query.toLowerCase()):true; const ms=status==="all"?true:a.status===status; const mc=channel==="all"?true:a.channel===channel; const mf=focus==="all"?true:focus==="urgent"?isOverdue(a)||a.priority==="Critical":focus==="review"?["review","draft"].includes(a.status):focus==="publishing"?["approved","scheduled"].includes(a.status):focus==="brand"?a.brandScore<80:focus==="growth"?a.rank>10||a.clicks<100:true; return mq&&ms&&mc&&mf}),[store.articles,query,status,channel,focus]);
 const overdue=store.articles.filter(isOverdue); const review=store.articles.filter(a=>["review","draft"].includes(a.status)); const ready=store.articles.filter(a=>canPublish(a,store.tasks,store.rules)); const advance=React.useCallback((id:string)=>commit(d=>{d.articles=d.articles.map(a=>a.id===id?{...a,status:nextStatus(a.status),updatedAt:new Date().toISOString()}:a)},"advance",`Advanced article ${id}`),[commit]); const archive=React.useCallback((id:string)=>commit(d=>{d.articles=d.articles.map(a=>a.id===id?{...a,status:"archived",updatedAt:new Date().toISOString()}:a)},"archive",`Archived article ${id}`),[commit]); const remove=React.useCallback((id:string)=>commit(d=>{d.articles=d.articles.filter(a=>a.id!==id); d.tasks=d.tasks.filter(t=>t.articleId!==id)},"delete",`Deleted article ${id}`),[commit]);
 return <Shell><main data-market-os-root className="mx-auto max-w-[1900px] space-y-6 p-4 lg:p-8"><Header total={store.articles.length} urgent={overdue.length} review={review.length} ready={ready.length} onReset={reset}/><section className="grid gap-4 md:grid-cols-2 xl:grid-cols-6"><Metric label="Articles" value={String(store.articles.length)} sub="Active workspace"/><Metric label="Overdue" value={String(overdue.length)} sub="Production risk" tone="red"/><Metric label="Review" value={String(review.length)} sub="Approval queue" tone="amber"/><Metric label="Ready" value={String(ready.length)} sub="Publishable" tone="emerald"/><Metric label="Clusters" value={String(store.clusters.length)} sub="Organic strategy"/><Metric label="Blocked tasks" value={String(store.tasks.filter(t=>t.status==='blocked').length)} sub="Execution blockers" tone="red"/></section><Filters query={query} setQuery={setQuery} status={status} setStatus={setStatus} channel={channel} setChannel={setChannel} view={view} setView={setView} focus={focus} setFocus={setFocus}/><Gateway/><SignalLibrary/>{view==="command"?<div className="grid gap-5 xl:grid-cols-[1.25fr_.75fr]"><Pipeline items={filtered} store={store} onAdvance={advance} onArchive={archive}/><Intelligence store={store}/></div>:null}{view==="pipeline"?<Pipeline items={filtered} store={store} onAdvance={advance} onArchive={archive}/>:null}{view==="calendar"?<CalendarMini items={filtered}/>:null}{view==="intelligence"?<Intelligence store={store}/>:null}{view==="table"||view==="command"?<Panel className="p-5"><Section eyebrow="Article inventory" title="SEO work table" desc="Open, edit, advance, archive or delete articles. All changes sync with subpages." action={<Button href="/market-os/seo-blog-workspace/create" kind="primary">+ Create article</Button>}/><div className="mt-5 space-y-3">{filtered.map(a=><ArticleRow key={a.id} article={a} tasks={store.tasks} onAdvance={()=>advance(a.id)} onArchive={()=>archive(a.id)} onDelete={()=>remove(a.id)}/>)}{filtered.length===0?<div className="rounded-3xl border border-dashed border-slate-300 bg-white p-10 text-center"><h3 className="text-2xl font-black text-slate-950">No article matches this view.</h3><p className="mt-2 text-sm font-semibold text-slate-9500">Clear filters or create a new SEO item.</p><div className="mt-5"><Button href="/market-os/seo-blog-workspace/create" kind="primary">+ Create article</Button></div></div>:null}</div></Panel>:null}<Panel className="p-5"><Section eyebrow="Execution log" title="Recent SEO operations" desc="Trace of decisions and actions performed across SEO Blog workspace."/><div className="mt-5 grid gap-3 md:grid-cols-2 xl:grid-cols-4">{store.logs.slice(0,8).map(l=><div key={l.id} className="rounded-2xl border border-slate-200 bg-slate-50 p-4"><p className="text-xs font-black uppercase tracking-wider text-slate-500">{l.action}</p><p className="mt-2 text-sm font-black text-slate-950">{l.entity}</p><p className="mt-1 text-xs font-bold leading-5 text-slate-9500">{l.detail}</p></div>)}</div></Panel></main></Shell>
}
